function DocsToc({ headings = [], minHeadings = 3 } = {}) {
  const { div, nav, a, span } = tags;
  if (headings.length < minHeadings) return div();

  const [activeId, setActiveId] = createSignal(headings[0]?.id || '');

  const container = div({ class: css('_sticky _top[80px] _flex _col _gap2 _py4') });
  container.appendChild(span({ class: css('_caption _fgmutedfg _uppercase _ls[0.06em] _pb2') }, 'On this page'));

  const navEl = nav({ class: css('_flex _col _gap0 _borderL _bcborder _pl3 _relative') });
  const indicator = div({ class: css('_absolute _left[-1px] _w[2px] _h[20px] _bgprimary _r1 _trans[top_0.15s]') });
  indicator.style.top = '0px';
  navEl.appendChild(indicator);

  headings.forEach((h, i) => {
    const linkEl = a({
      href: `#${h.id}`,
      class: css('_textsm _fgmutedfg _nounder _py1 _trans _hover:fgfg'),
      onclick: (e) => {
        e.preventDefault();
        document.getElementById(h.id)?.scrollIntoView({ behavior: 'smooth' });
      }
    }, h.label);
    navEl.appendChild(linkEl);
  });

  container.appendChild(navEl);

  // Scroll spy with IntersectionObserver
  onMount(() => {
    const observer = new IntersectionObserver((entries) => {
      for (const entry of entries) {
        if (entry.isIntersecting) setActiveId(entry.target.id);
      }
    }, { rootMargin: '-80px 0px -70% 0px' });
    headings.forEach(h => {
      const el = document.getElementById(h.id);
      if (el) observer.observe(el);
    });
    onDestroy(() => observer.disconnect());
  });

  // Update indicator position
  createEffect(() => {
    const idx = headings.findIndex(h => h.id === activeId());
    indicator.style.top = `${idx * 28 + 4}px`;
  });

  return container;
}
